+    } else {
+        sa.sa_flags |= libc::SA_RESTART;
+    }
+    // SAFETY: set the modified action.
+    let rc = unsafe {
+        libc::syscall(
+            libc::SYS_rt_sigaction,
+            sig,
+            &sa as *const libc::sigaction,
+            std::ptr::null::<libc::sigaction>(),
+            std::mem::size_of::<libc::c_ulong>(),
+        ) as c_int
+    };
+    if rc != 0 { -1 } else { 0 }
