+        let ret = unsafe {
+            wcrtomb(
+                if dst.is_null() {
+                    buf.as_mut_ptr() as *mut c_char
+                } else if written + 4 <= len {
+                    dst.add(written)
+                } else {
+                    buf.as_mut_ptr() as *mut c_char
+                },
+                wc,
+                ps,
+            )
