+    if pending != 0 {
+        // We have a pending low surrogate to deliver.
+        C16_SURROGATE.with(|cell| cell.set(0));
+        if !pc16.is_null() {
+            unsafe { *pc16 = pending as u16 };
+        }
+        return usize::MAX - 2; // (size_t)-3: indicates stored character returned
