+            unsafe { *pc16 = high as u16 };
+        }
+        // Store low surrogate for next call.
+        C16_SURROGATE.with(|cell| cell.set(low));
+        return ret;
+    }
+
+    if !pc16.is_null() {
+        unsafe { *pc16 = c32 as u16 };
+    }
+    ret
